func (ctl *Control) Start() {
	loginRespMsg := &msg.LoginResp{
		Version:	version.Full(),
		RunID:		ctl.runID,
		Error:		"",
	}
	_ = msg.WriteMsg(ctl.conn, loginRespMsg)

	go func() {
		for i := 0; i < ctl.poolCount; i++ {

			_ = ctl.msgDispatcher.Send(&msg.ReqWorkConn{})
		}
	}()
	go ctl.worker()
}
